import{_ as n,C as t,o as a,c as i,a3 as o,b as r,w as c,a as d,E as p,a4 as s}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Namespace clore::net::openai","description":"命名空间 clore::net::openai 封装了与 OpenAI 兼容的大语言模型（LLM）进行异步通信的核心能力。它对外暴露三个关键函数：call_completion_async、call_llm_async 和 call_structured_async，分别对应补全请求、通用 LLM 调用和结构化输出请求。所有函数均以非阻塞方式工作，通过接受 kota::event_loop 引用来调度异步事件，并在启动后立即返回一个非负整数句柄，用于后续的跟踪、取消或查询。参数设计覆盖了模型标识、用户提示、系统提示、最大生成令牌数以及输出格式描述等典型输入。","frontmatter":{"title":"Namespace clore::net::openai","description":"命名空间 clore::net::openai 封装了与 OpenAI 兼容的大语言模型（LLM）进行异步通信的核心能力。它对外暴露三个关键函数：call_completion_async、call_llm_async 和 call_structured_async，分别对应补全请求、通用 LLM 调用和结构化输出请求。所有函数均以非阻塞方式工作，通过接受 kota::event_loop 引用来调度异步事件，并在启动后立即返回一个非负整数句柄，用于后续的跟踪、取消或查询。参数设计覆盖了模型标识、用户提示、系统提示、最大生成令牌数以及输出格式描述等典型输入。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/net/openai/index.md","filePath":"zh/clore/namespaces/clore/net/openai/index.md"}'),m={name:"zh/clore/namespaces/clore/net/openai/index.md"};function h(u,e,_,f,y,b){const l=t("Mermaid");return a(),i("div",null,[e[1]||(e[1]=o('<h1 id="namespace-clore-net-openai" tabindex="-1">Namespace <code>clore::net::openai</code> <a class="header-anchor" href="#namespace-clore-net-openai" aria-label="Permalink to &quot;Namespace `clore::net::openai`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>命名空间 <code>clore::net::openai</code> 封装了与 <code>OpenAI</code> 兼容的大语言模型（LLM）进行异步通信的核心能力。它对外暴露三个关键函数：<code>call_completion_async</code>、<code>call_llm_async</code> 和 <code>call_structured_async</code>，分别对应补全请求、通用 LLM 调用和结构化输出请求。所有函数均以非阻塞方式工作，通过接受 <code>kota::event_loop</code> 引用来调度异步事件，并在启动后立即返回一个非负整数句柄，用于后续的跟踪、取消或查询。参数设计覆盖了模型标识、用户提示、系统提示、最大生成令牌数以及输出格式描述等典型输入。</p><p>在架构上，<code>clore::net::openai</code> 位于网络抽象层，负责将高层业务逻辑与底层 HTTP/<code>WebSocket</code> 通信解耦。它假定调用方提供一个活跃的事件循环，并依赖其回调机制传递完成信号或错误码，从而避免阻塞调用线程。通过统一返回句柄的设计，该命名空间使得上层代码可以并发管理多个请求，而不必关注具体的网络 I/O 细节，是整个库中异步 LLM 交互的标准入口。</p><h2 id="diagram" tabindex="-1">Diagram <a class="header-anchor" href="#diagram" aria-label="Permalink to &quot;Diagram&quot;">​</a></h2>',5)),(a(),r(s,null,{default:c(()=>[p(l,{id:"mermaid-15",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20NS%5B%22openai%22%5D%0A%20%20%20%20NSC0%5B%22detail%22%5D%0A%20%20%20%20NS%20--%3E%20NSC0%0A%20%20%20%20NSC1%5B%22protocol%22%5D%0A%20%20%20%20NS%20--%3E%20NSC1%0A%20%20%20%20NSC2%5B%22schema%22%5D%0A%20%20%20%20NS%20--%3E%20NSC2%0A"})]),fallback:c(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="subnamespaces" tabindex="-1">Subnamespaces <a class="header-anchor" href="#subnamespaces" aria-label="Permalink to &quot;Subnamespaces&quot;">​</a></h2><ul><li><a href="./detail/"><code>clore::net::openai::detail</code></a></li><li><a href="./protocol/"><code>clore::net::openai::protocol</code></a></li><li><a href="./schema/"><code>clore::net::openai::schema</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-openai-call-completion-async" tabindex="-1"><code>clore::net::openai::call_completion_async</code> <a class="header-anchor" href="#clore-net-openai-call-completion-async" aria-label="Permalink to &quot;`clore::net::openai::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:748</code></p><p>Definition: <code>network/openai.cppm:775</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::openai::call_completion_async</code> 启动一个异步的补全请求。它接受一个 <code>int</code> 类型的参数（该参数的含义取决于调用上下文，通常标识要完成的序列或请求）以及一个 <code>kota::event_loop &amp;</code> 事件循环引用，异步操作将在该事件循环上调度。该函数返回一个 <code>int</code>，用于标记或跟踪已提交的异步操作，调用方可将此值用于后续的取消或结果查询。调用方需确保事件循环在异步操作完成前保持运行状态。</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to initiate an async completion request to <code>OpenAI</code></li><li>used with an event loop for lightweight concurrency</li></ul><h3 id="clore-net-openai-call-llm-async" tabindex="-1"><code>clore::net::openai::call_llm_async</code> <a class="header-anchor" href="#clore-net-openai-call-llm-async" aria-label="Permalink to &quot;`clore::net::openai::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:752</code></p><p>Definition: <code>network/openai.cppm:782</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>函数 <code>clore::net::openai::call_llm_async</code> 发起一次对 <code>OpenAI</code> 兼容大语言模型（LLM）的异步调用。调用者需要提供模型标识符、输入提示、一个整型参数（通常为最大生成令牌数）以及一个 <code>kota::event_loop</code> 引用用于调度异步事件。函数在启动请求后立即返回一个非负整数句柄，该句柄可用来查询或取消本次请求；若返回负值则表示发起失败。调用者不应假设请求完成的顺序，所有完成信号均通过传入的事件循环传递。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by higher-level <code>OpenAI</code> API functions</li><li>Used to perform LLM calls asynchronously in an event-driven context</li></ul><h3 id="clore-net-openai-call-llm-async-1" tabindex="-1"><code>clore::net::openai::call_llm_async</code> <a class="header-anchor" href="#clore-net-openai-call-llm-async-1" aria-label="Permalink to &quot;`clore::net::openai::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:758</code></p><p>Definition: <code>network/openai.cppm:793</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>调用 <code>clore::net::openai::call_llm_async</code> 向 <code>OpenAI</code> 兼容的 LLM 发起一次异步请求。它接受三个 <code>std::string_view</code> 参数，通常分别代表模型标识、用户输入和可选的系统提示，以及一个 <code>kota::event_loop &amp;</code> 引用，用于调度异步完成。该函数不会阻塞调用方线程，而是立即返回。</p><p>返回的 <code>int</code> 值标识此次请求，可用于后续跟踪或取消（例如通过 <code>call_completion_async</code>）。调用方必须保证传入的字符串视图在异步操作完成前保持有效，且事件循环必须处于运行状态，否则行为未定义。返回的错误码通过事件循环回调机制传递，不在函数返回值中体现。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>使用异步协程进行 LLM 调用</li><li>与 <code>kota::event_loop</code> 集成</li></ul><h3 id="clore-net-openai-call-structured-async" tabindex="-1"><code>clore::net::openai::call_structured_async</code> <a class="header-anchor" href="#clore-net-openai-call-structured-async" aria-label="Permalink to &quot;`clore::net::openai::call_structured_async`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:765</code></p><p>Definition: <code>network/openai.cppm:805</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p>发起一个对 <code>OpenAI</code> 结构化输出的异步调用。该函数接受三个字符串视图参数（通常对应系统提示、用户提示以及输出格式描述或 JSON Schema）和一个 <code>kota::event_loop</code> 引用，返回一个 <code>int</code> 表示异步操作的句柄或状态。调用方负责提供有效的提示文本、期望的结构化格式描述以及一个运行中的事件循环；返回值可用于后续查询或取消操作。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>用于需要结构化响应的 <code>OpenAI</code> LLM 调用</li><li>与事件循环配合使用以支持异步等待</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net</a></li><li><a href="./detail/">Namespace clore::net::openai::detail</a></li><li><a href="./protocol/">Namespace clore::net::openai::protocol</a></li><li><a href="./schema/">Namespace clore::net::openai::schema</a></li></ul>',34))])}const P=n(m,[["render",h]]);export{g as __pageData,P as default};
